    @Test
    fun testToListWithDestination() = runTest {
        val sh = MutableSharedFlow<Int>(replay = 2)
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sh.toList(acc)
        }

        // Emit some values
        sh.emit(1)
        sh.emit(2)
        sh.emit(3)

        // Cancel the job to stop collecting
        job.cancel()

        // Verify that values were collected into the provided list
        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test
    fun testToSetWithDestination() = runTest {
        val sh = MutableSharedFlow<Int>(replay = 2)
        val acc = mutableSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sh.toSet(acc)
        }

        // Emit some values (with duplicates)
        sh.emit(1)
        sh.emit(2)
        sh.emit(1)
        sh.emit(3)

        // Cancel the job to stop collecting
        job.cancel()

        // Verify that values were collected into the provided set
        assertEquals(setOf(1, 2, 3), acc)
    }
}"}

